var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"조금 늦었으나, 구원기사단의 고유무장에 관한 인계 절차는 무사히 끝마쳤습니다.","JPN":"少し遅くなりましたが、救世騎士団の固有武装については無事引き渡しが終わりました。","ENG":"The handover process for the Knights of Redemption's Unique Gear is complete. A bit late, but everything went smoothly.","TWN":"雖然有些晚了，但關於救贖騎士團的專屬武裝的交接程式已經順利完成。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"더 이상 이쪽을 신경 쓰실 필요는 없을 것 같군요.","JPN":"もうこちらを気にする必要はなさそうですね。","ENG":"You won't need to worry about things on this end anymore.","TWN":"我想你不必再操心這邊的事情了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"죄송합니다. 설마 이런 식으로 일을 진행했을 줄은 몰랐어요.","JPN":"申し訳ありません。まさかこういう風になるとは思わなかったもので。","ENG":"I'm sorry. I had no idea things would be handled this way.","TWN":"對不起，我沒想到事情會以這種方式進行。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"로터스 관리국 쪽에서 흔쾌히 허락해줬다고 들었는데… 설마 주먹구구식이었을 줄은.","JPN":"ロータス管理局が快諾してくれたと聞きましたが……まさかこれほど大ざっぱだったとは。","ENG":"I heard the Lotus Administration approved it without hesitation... but I didn't think it would be so sloppy.","TWN":"聽說洛德斯管理局那邊爽快地答應了……沒想到竟然是草率行事。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"다른 시니어 분들도 동의한 내용이니 상관없습니다.","JPN":"他のシニアも同意された内容ですので、構いません。","ENG":"It's fine. The other Seniors agreed as well.","TWN":"其他Senior也同意，所以沒關係。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"비록 연구욕이 불타오른다며 환희에 찬 시니어님의 의지가 다시금 꺾여버렸으나, 사소한 문제죠.","JPN":"研究意欲に火が付いたと大喜びしていたシニアの意志が、またへし折れてしまいましたが、些細なことです。","ENG":"Though one of them, who was practically vibrating with excitement, had his hopes dashed again. Still, a minor issue.","TWN":"雖然研究欲望燃燒起來，充滿歡喜的Senior的意志再次被打擊，但這只是小問題。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……거듭 죄송합니다.","JPN":"……本当に申し訳ありません。","ENG":"...Once again, my apologies.","TWN":"……再次非常抱歉。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"아닙니다. 오히려 시국으로 인해 큰 도움을 드릴 수 없어 부끄러울 따름이군요.","JPN":"いいえ。むしろこちらの状況であまり助けになれないのがお恥ずかしいかぎりです。","ENG":"No need. If anything, I'm ashamed we couldn't be of more help given the situation.","TWN":"不是的。反而因為時局無法給予太多幫助，感到有些慚愧。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"부디, 건투를 빌겠습니다.","JPN":"ご健闘を祈ります。","ENG":"I wish you good luck.","TWN":"祝你好運，希望你能成功。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哈……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이쪽은 아직 별다른 움직임이 없습니다. 다른 쪽은 어떤가요?","JPN":"こちらはまだ特に動きは見えません。そちらはいかがですか？","ENG":"Nothing to report on this end yet. What about your side?","TWN":"這邊暫時沒有什麼動靜。另一邊怎麼樣？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"이쪽도 문제없습니다.","JPN":"こちらも問題ありません。","ENG":"All clear here as well.","TWN":"我們這邊也沒問題。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"외부 구역에도 감시 장비를 대동했으니, 무슨 일이 있어도 즉각적으로 대응 가능해요.","JPN":"外部区域にも監視装備を持って行きましたから、何があってもただちに対応可能です。","ENG":"We've got surveillance equipment covering the outer perimeter. We'll respond immediately if anything happens.","TWN":"外部區域也配備了監控設備，所以無論發生什麼事情都能立即應對。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"본부. 마찬가지로 이상 없습니다.","JPN":"本部。同じく異常なしです。","ENG":"This is HQ. No abnormalities here either.","TWN":"總部，一樣沒有異常。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"혹시라도 적의 움직임이 포착되면 연락 드리겠습니다.","JPN":"敵の動きを捉えたらご連絡いたします。","ENG":"I'll contact you if we detect any enemy movement.","TWN":"如果發現敵人的動向，我會聯絡你。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"하아암…….","JPN":"ふああー……","ENG":"*Yawn...*","TWN":"哈啊啊……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경. 집중해주세요. 언제 레드시프트가 습격해올지 모르는 상황이라고요.","JPN":"リブ卿。集中してください。いつレッドシフトが襲撃してくるかわからない状況なんですよ。","ENG":"Dame Liv, please focus. We don't know when Red Shift might attack.","TWN":"莉芙。請集中注意力。現在是紅移隨時可能襲來的情況。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그것 말인데, 이렇게 하루 종일 죽치고 있는 게 무슨 의미가 있어?","JPN":"それなんだけど、こうやって一日中待機してるのって何か意味があるの？","ENG":"That's what I'm saying. What's the point of sitting around like this all day?","TWN":"話說，整天待在這裡有什麼意義呢？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"당장 걔네가 언제 쳐들어올지도 모르잖아.","JPN":"今すぐあいつらが攻撃してくるかもしれないじゃん。","ENG":"It's not like we have any idea when they'll show up.","TWN":"他們隨時可能會進攻，我們也不知道什麼時候會發生。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"작전 브리핑 때 공유 받은 내용이잖아요. 그새 까먹으신 건가요?","JPN":"作戦会議で共有していただいた内容じゃないですか。もう忘れたんですか？","ENG":"This was all covered in the briefing. Did you already forget?","TWN":"這是在作戰簡報時分享的內容。你這麼快就忘了嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그런 걸 했었나?","JPN":"そんなのやったっけ？","ENG":"We had a briefing?","TWN":"有那樣的事嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"크흠! 다시 한번 설명해 드릴 테니 이번에는 잘 기억해주세요.","JPN":"コホン！　もう一度説明しますから、今度はちゃんと覚えててくださいね。","ENG":"Ahem! Then let me go over it again. This time, please pay attention.","TWN":"咳咳！我會再解釋一次，這次請記住。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"암암리에 활동하던 레드시프트가 직접적인 움직임을 보인 이유.","JPN":"密かに活動していたレッドシフトが直接動き出した理由。","ENG":"The reason Red Shift finally made a move after all their covert activity.","TWN":"暗中活動的紅移開始直接行動的原因。"},"stage":{"bg":"MS_1203","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"다른 이유도 있겠지만, 결정적인 건 관리국이 그들을 주시할 수 없는 상황이기 때문입니다.","JPN":"他にもあるでしょうけど、決定的な理由は管理局が彼らを注視できない状況だからです。","ENG":"There might be other reasons, but the biggest one is that the Administration can't monitor them right now.","TWN":"雖然還有其他原因，但最關鍵的是管理局無法監視他們的情況。"},"stage":{"bg":"MS_1203","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"기사단 본부를 공격한 것도 이와 일맥상통하죠.","JPN":"騎士団の本部を攻撃したのも、これと繋がります。","ENG":"That's also why they attacked the Order's HQ.","TWN":"攻擊騎士團總部也是與此一脈相承的。"},"stage":{"bg":"MS_1203","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};